        try:
            data = json.loads(RECIPE_RUNS_PATH.read_text())
            runs = data if isinstance(data, list) else []
        except (json.JSONDecodeError, OSError):
            runs = []
        runs = runs[-limit:]
        self._send_json({"runs": runs, "total": len(runs)})

